import re
from dataclasses import dataclass

@dataclass
class ParsedAction:
    tool: str
    input: str

def parse_action(llm_output: str) -> ParsedAction | None:
    # Bracket-style: search[query text]
    m = re.search(r'Action:\s*(\w[\w_-]*)\[(.+?)\]', llm_output, re.DOTALL)
    if m:
        return ParsedAction(tool=m.group(1).strip(), input=m.group(2).strip())
    # Paren-style: search("query text")
    m = re.search(r'Action:\s*(\w[\w_-]*)\("(.+?)"\)', llm_output, re.DOTALL)
    if m:
        return ParsedAction(tool=m.group(1).strip(), input=m.group(2).strip())
    return None

def format_parse_error(llm_output: str, available_tools: list[str]) -> str:
    return (
        f"Error: could not parse an action from your output.\n"
        f"Your output was: {llm_output[:200]!r}\n"
        f"Available tools: {available_tools}\n"
        "Use the exact format: Action: tool_name[tool_input]"
    )

def format_observation(result: str) -> str:
    """Wrap tool result in the Observation: prefix for the scratchpad."""
    return "Observation: " + result + "\n"

def execute_action(action: ParsedAction, tools: dict) -> str:
    if action.tool not in tools:
        available = list(tools.keys())
        return f"Error: '{action.tool}' is not a valid tool. Available: {available}"
    try:
        result = tools[action.tool](action.input)
        # Truncate very long results to avoid filling the context window
        if len(result) > 1500:
            result = result[:1500] + "\n[... result truncated ...]"
        return result
    except Exception as e:
        return f"Error: {action.tool} raised {type(e).__name__}: {e}"

import tiktoken

def count_tokens(text: str, model: str = "gpt-4o-mini") -> int:
    enc = tiktoken.encoding_for_model(model)
    return len(enc.encode(text))

def trim_scratchpad(scratchpad: str, max_tokens: int = 6000,
                    model: str = "gpt-4o-mini") -> str:
    if count_tokens(scratchpad, model) <= max_tokens:
        return scratchpad
    lines = scratchpad.splitlines(keepends=True)
    obs_indices = [i for i, l in enumerate(lines) if l.startswith("Observation:")]
    # Drop oldest observation blocks until under budget
    while obs_indices and count_tokens("".join(lines), model) > max_tokens:
        drop_idx = obs_indices.pop(0)
        lines[drop_idx] = "Observation: [truncated to save context]\n"
    return "".join(lines)
